import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office - Quote (Premium Calculation)", () => {
  // Simplest case: empty quote
  it.todo("should return 5G premium (just processing fee) for empty item list");

  // Single item base premiums (no modifiers other than first-insurance per-item surcharge)
  it.todo("should calculate premium for a single plain sword for a newcomer");
  it.todo("should calculate premium for a single plain amulet for a newcomer");
  it.todo("should calculate premium for a single plain staff for a newcomer");
  it.todo("should calculate premium for a single plain potion for a newcomer");
  it.todo("should calculate premium for a single rune component for a newcomer");
  it.todo("should calculate premium for a single moonstone component for a newcomer");

  // Multiple items, base premiums
  it.todo("should sum base premiums for a cursed sword plus plain amulet (before fee)");
  it.todo("should calculate premium for a plain sword plus plain amulet for a newcomer");

  // Item-specific modifiers
  it.todo("should add 50% surcharge to base premium for a cursed item");
  it.todo("should add 30% surcharge to base premium for a highly enchanted item (enchantment >= 5)");
  it.todo("should apply both cursed and high-enchantment surcharges to the same item");

  // Component blocks
  it.todo("should charge 50G for 2 runes (no block)");
  it.todo("should charge 60G base for 3 alike runes as a block");
  it.todo("should charge 100G for 4 runes (one block of 3 plus 1 single)");
  it.todo("should charge 175G for 7 runes (two blocks of 3 plus 1 single)");
  it.todo("should charge 75G for 2 runes plus 1 moonstone (no block, mixed types)");
  it.todo("should charge 120G for 3 runes plus 3 moonstones (two separate blocks)");

  // Policy-wide modifiers
  it.todo("should apply 20% loyalty discount for long-standing customer (>= 2 years)");
  it.todo("should apply 10% first-insurance surcharge per item for a newcomer");
  it.todo("should apply 15% follow-up contract discount on subsequent quotes");

  // Combined modifiers (canonical examples from spec)
  it.todo("should calculate 165G for newcomer with cursed sword (100 + 50 + 10 + 5)");
  it.todo("should calculate 160G for long-standing customer 2nd contract with cursed sword ench 7");

  // Rounding
  it.todo("should round the final premium UP to whole G (in MHPCO's favor)");
  it.todo("should round 197.5G premium up to 198G");
});

describe("MHPCO Claim Office - Claim (Damage Payout)", () => {
  // Simplest case
  it.todo("should pay out damage minus 100G deductible for a plain item");
  it.todo("should pay out 400G for a regular sword ench 3 with 500G damage");

  // Component claims (no special clauses)
  it.todo("should pay out 100G for a rune with 200G damage (250G insured, minus deductible)");

  // Special clauses
  it.todo("should reimburse 50% of damage then deduct 100G for items with enchantment >= 8");
  it.todo("should pay out 400G for a steel sword ench 9 with 1000G damage");
  it.todo("should fully reimburse dragon-material items then deduct 100G");
  it.todo("should pay out 700G for a dragon sword ench 5 with 800G damage");
  it.todo("should apply 50% rule (not dragon rule) when both apply, paying 400G for dragon sword ench 8 with 1000G damage");

  // Multiple damage entries
  it.todo("should apply own deductible to each damage entry when one event damages multiple items");

  // Cap (2x unmodified insurance sum)
  it.todo("should cap total payout at 2x sum of unmodified insurance values across the policy");
  it.todo("should reduce payout when remaining cap is less than computed payout");
  it.todo("should share the cap across multiple successive claims on the same policy");

  // Rounding
  it.todo("should round the final payout DOWN to whole G");
  it.todo("should round a 350.5G payout down to 350G");
});

describe("MHPCO Claim Office - CLI", () => {
  it.todo("should read JSON from stdin and write a results JSON to stdout");
  it.todo("should produce a results array with one entry per step");
  it.todo("should output {premium: N} for a quote step");
  it.todo("should output {payout: N, remainingCap: N} for a claim step");
  it.todo("should track remaining cap across successive claims on the same policy");
  it.todo("should reference the policy by step index for claim operations");
});

describe("MHPCO Claim Office - Errors", () => {
  it.todo("should exit non-zero and write to stderr for an unknown item type in a quote");
  it.todo("should exit non-zero and write to stderr when a claim references an item not in the policy");
  it.todo("should exit non-zero and write to stderr for a damage entry with negative amount");
  it.todo("should exit non-zero and write to stderr when damages contain more entries of a type than the policy covers");
});
